import argparse
from pathlib import Path
HTML = '<!doctype html>\n<html>\n<head>\n  <meta charset="utf-8"/>\n  <title>Slide Human Audit</title>\n  <style>\n    body { font-family: Arial, sans-serif; margin: 16px; }\n    .row { display:flex; gap:16px; align-items:flex-start; }\n    .panel { flex: 1; }\n    img { max-width: 100%; border: 1px solid #ddd; }\n    textarea { width: 100%; height: 140px; }\n    .meta { color:#333; font-size: 14px; margin: 8px 0; }\n    .btn { padding: 8px 12px; margin-right: 8px; }\n    .pill { display:inline-block; padding:2px 8px; border:1px solid #aaa; border-radius:999px; font-size:12px; margin-right:6px; }\n    table { border-collapse: collapse; }\n    td { padding: 4px 8px; vertical-align: top; }\n  </style>\n</head>\n<body>\n<h2>Human Audit: Educational Slides</h2>\n<div class="meta">\n  Load <span class="pill">audit_slides.csv</span> (same folder) and label each slide. When done, download <span class="pill">audit_responses.csv</span>.\n</div>\n\n<div>\n  <button class="btn" id="btnPrev">Prev</button>\n  <button class="btn" id="btnNext">Next</button>\n  <button class="btn" id="btnSave">Download responses CSV</button>\n  <span id="status" class="meta"></span>\n</div>\n\n<hr/>\n\n<div class="row">\n  <div class="panel">\n    <div id="meta"></div>\n    <img id="slideImg" alt="Slide image"/>\n  </div>\n\n  <div class="panel">\n    <h3>Labels</h3>\n    <table>\n      <tr>\n        <td>Concepts correct/useful?</td>\n        <td>\n          <select id="qConcept">\n            <option value="">(skip)</option>\n            <option value="yes">yes</option>\n            <option value="no">no</option>\n          </select>\n        </td>\n      </tr>\n      <tr>\n        <td>Triples correct/useful?</td>\n        <td>\n          <select id="qTriple">\n            <option value="">(skip)</option>\n            <option value="yes">yes</option>\n            <option value="no">no</option>\n          </select>\n        </td>\n      </tr>\n      <tr>\n        <td>Key info mainly in image?</td>\n        <td>\n          <select id="qImageDominant">\n            <option value="">(skip)</option>\n            <option value="yes">yes</option>\n            <option value="no">no</option>\n          </select>\n        </td>\n      </tr>\n    </table>\n\n    <h3>Notes (optional)</h3>\n    <textarea id="notes" placeholder="Short notes: what was wrong / why?"></textarea>\n  </div>\n</div>\n\n<script>\nasync function loadCSV(path) {\n  const txt = await (await fetch(path)).text();\n  const lines = txt.trim().split(/\\r?\\n/);\n  const header = lines[0].split(",");\n  const rows = [];\n  for (let i=1;i<lines.length;i++){\n    // naive CSV parse: assumes no commas inside fields\n    const cols = lines[i].split(",");\n    const obj = {};\n    header.forEach((h,idx)=> obj[h] = (cols[idx]||""));\n    rows.push(obj);\n  }\n  return rows;\n}\n\nfunction toCSV(rows){\n  if(rows.length===0) return "";\n  const header = Object.keys(rows[0]);\n  const lines = [header.join(",")];\n  for(const r of rows){\n    const line = header.map(h => (r[h]??"").toString().replaceAll("\\n"," ").replaceAll(",",";"));\n    lines.push(line.join(","));\n  }\n  return lines.join("\\n");\n}\n\nlet slides = [];\nlet idx = 0;\nlet responses = {}; // key -> response\n\nfunction keyOf(s){ return `${s.lecture}__${s.slide_id}`; }\n\nfunction render(){\n  const s = slides[idx];\n  const k = keyOf(s);\n\n  document.getElementById("meta").innerHTML = `\n    <div class="meta"><b>${s.group}</b> | <b>${s.lecture}</b> / <b>${s.slide_id}</b></div>\n    <div class="meta">concept_ocr_rate=${s.concept_ocr_rate} | concept_transcript_rate=${s.concept_transcript_rate} | concept_neither_rate=${s.concept_neither_rate} | triple_valid_rate=${s.triple_valid_rate}</div>\n    <div class="meta">image_path: ${s.image_path}</div>\n  `;\n\n  // Use file:// for local paths: browsers may block direct access.\n  // If it doesn\'t display, copy the image into a relative folder and update image_path accordingly.\n  document.getElementById("slideImg").src = s.image_path;\n\n  const r = responses[k] || {};\n  document.getElementById("qConcept").value = r.concepts || "";\n  document.getElementById("qTriple").value = r.triples || "";\n  document.getElementById("qImageDominant").value = r.image_dominant || "";\n  document.getElementById("notes").value = r.notes || "";\n\n  document.getElementById("status").textContent = `Slide ${idx+1}/${slides.length}`;\n}\n\nfunction saveCurrent(){\n  const s = slides[idx];\n  const k = keyOf(s);\n  responses[k] = {\n    concepts: document.getElementById("qConcept").value,\n    triples: document.getElementById("qTriple").value,\n    image_dominant: document.getElementById("qImageDominant").value,\n    notes: document.getElementById("notes").value,\n  };\n}\n\ndocument.getElementById("btnPrev").onclick = () => { saveCurrent(); idx = Math.max(0, idx-1); render(); };\ndocument.getElementById("btnNext").onclick = () => { saveCurrent(); idx = Math.min(slides.length-1, idx+1); render(); };\n\ndocument.getElementById("btnSave").onclick = () => {\n  saveCurrent();\n  const outRows = slides.map(s => {\n    const k = keyOf(s);\n    const r = responses[k] || {};\n    return {\n      group: s.group,\n      lecture: s.lecture,\n      slide_id: s.slide_id,\n      image_path: s.image_path,\n      concepts_correct: r.concepts || "",\n      triples_correct: r.triples || "",\n      image_dominant: r.image_dominant || "",\n      notes: r.notes || "",\n    };\n  });\n\n  const blob = new Blob([toCSV(outRows)], {type:"text/csv;charset=utf-8"});\n  const a = document.createElement("a");\n  a.href = URL.createObjectURL(blob);\n  a.download = "audit_responses.csv";\n  a.click();\n};\n\n(async () => {\n  slides = await loadCSV("audit_slides.csv");\n  render();\n})();\n</script>\n</body>\n</html>\n'

def main():
    ap = argparse.ArgumentParser()
    ap.add_argument('--out', required=True)
    args = ap.parse_args()
    out_dir = Path(args.out)
    out_dir.mkdir(parents=True, exist_ok=True)
    (out_dir / 'audit_form.html').write_text(HTML, encoding='utf-8')
    print('[OK] Wrote:', out_dir / 'audit_form.html')
if __name__ == '__main__':
    main()